+    #[test]
+    fn test_create_table_as_select_in_attached_schema_reads_parent_main_source() {
+        let dir = tempfile::tempdir().unwrap();
+        let aux_path = dir.path().join("aux.db");
+        let aux_path_sql = aux_path.to_string_lossy().replace('\'', "''");
+
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE src (id INTEGER, value TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO src VALUES (1, 'main');").unwrap();
+        conn.execute(&format!("ATTACH DATABASE '{aux_path_sql}' AS aux;"))
+            .unwrap();
+        conn.execute("CREATE TABLE aux.src (id INTEGER, value TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO aux.src VALUES (1, 'aux');").unwrap();
+
+        conn.execute("CREATE TABLE aux.copy AS SELECT id, value FROM main.src;")
+            .unwrap();
+
+        let rows = conn
+            .query("SELECT id, value FROM aux.copy ORDER BY id;")
+            .unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(1));
+        assert_eq!(rows[0].values()[1], SqliteValue::Text("main".into()));
+    }
